	private static final JoinSearchCostModel COST_MODEL = new JoinSearchCostModel() {
		@Override
		public JoinSearchEstimate estimateFactor(JoinFactor factor) {
			double rows = switch (factor.groupId()) {
			case 0 -> 2.0;
			case 1 -> 3.0;
			case 2 -> 5.0;
			case 3 -> 11.0;
			default -> 17.0 + factor.groupId();
			};
			return new JoinSearchEstimate(rows, rows);
		}

		@Override
		public JoinSearchEstimate estimateJoin(JoinTree left, JoinSearchCost leftCost, JoinTree right,
				JoinSearchCost rightCost) {
			double widthPenalty = left.leafOrder().size() + 2.0 * right.leafOrder().size();
			double outputRows = Math.max(1.0,
					leftCost.outputRows() * rightCost.outputRows() / (2.0 + widthPenalty));
			double localWork = leftCost.outputRows() + 2.0 * rightCost.outputRows()
					+ leftCost.outputRows() * rightCost.outputRows();
			return new JoinSearchEstimate(outputRows, localWork);
		}
	};

