	@Test
	void repeatedMemoGroupOccurrencesRemainDistinctThroughSearch() throws ReflectiveOperationException {
		Constructor<JoinFactor> occurrenceConstructor = assertDoesNotThrow(
				() -> JoinFactor.class.getConstructor(int.class, int.class),
				"Join factors need a public occurrence ID distinct from their memo group ID");
		JoinFactor firstOccurrence = occurrenceConstructor.newInstance(10, 7);
		JoinFactor secondOccurrence = occurrenceConstructor.newInstance(11, 7);
		JoinRegion region = new JoinRegion(List.of(firstOccurrence, secondOccurrence),
				List.of(new JoinDependency(11, Set.of(10))));
		JoinTree legalTree = JoinTree.join(JoinTree.factor(10), JoinTree.factor(11));
		JoinTree reversedTree = JoinTree.join(JoinTree.factor(11), JoinTree.factor(10));

		JoinSearchResult result = new JoinSearchService(List.of(new ExhaustiveLegalJoinSearchContributor(2)))
				.search(JoinSearchRequest.complete(region, COST_MODEL));

		assertEquals(Set.of(10, 11), region.factorIds(), "Region identity must be occurrence-based");
		assertEquals(7, region.factor(10).groupId());
		assertEquals(7, region.factor(11).groupId());
		assertTrue(region.isLegal(legalTree));
		assertFalse(region.isLegal(reversedTree), "Dependencies must target one occurrence, not every use of group 7");
		assertFalse(region.isLegal(JoinTree.join(JoinTree.factor(10), JoinTree.factor(10))),
				"A legal self-join tree must contain each occurrence exactly once");
		assertEquals(JoinSearchCompleteness.COMPLETE, result.completeness());
		assertEquals(List.of(10, 11), result.winner().orElseThrow().tree().leafOrder());
		assertEquals(1L, result.distinctCandidateCount());
	}

	@Test
	void exhaustiveWinnerMatchesIndependentOracleForDisconnectedAndCorrelatedRegions() {
		ArrayList<JoinRegion> regions = new ArrayList<>();
		for (int factorCount = 1; factorCount <= 5; factorCount++) {
			regions.add(region(factorCount, List.of()));
		}
		regions.add(region(5, List.of(
				new JoinDependency(2, Set.of(0)),
				new JoinDependency(4, Set.of(1, 3)))));
		JoinSearchService service = new JoinSearchService(List.of(new ExhaustiveLegalJoinSearchContributor(5)));

		for (JoinRegion region : regions) {
			JoinSearchResult result = service.search(JoinSearchRequest.complete(region, COST_MODEL));
			OracleWinner oracle = bruteForceWinner(region, COST_MODEL);

			assertEquals(JoinSearchCompleteness.COMPLETE, result.completeness());
			assertEquals(oracle.tree(), result.winner().orElseThrow().tree(), "region=" + region);
			assertEquals(oracle.cost(), result.winner().orElseThrow().cost(), "region=" + region);
			assertTrue(result.distinctCandidateCount() > 0L);
		}
	}

