	@Test
	void subsetEnumerationEmitsEachOrientedBushyTreeOnceInDeterministicOrder() {
		JoinSearchRequest request = JoinSearchRequest.complete(region(4, List.of()), COST_MODEL);
		JoinSearchService service = new JoinSearchService(List.of(new ExhaustiveLegalJoinSearchContributor()));
		ArrayList<String> first = new ArrayList<>();
		ArrayList<String> second = new ArrayList<>();

		JoinSearchResult firstResult = service.search(request,
				candidate -> first.add(candidate.tree().canonicalForm()));
		JoinSearchResult secondResult = service.search(request,
				candidate -> second.add(candidate.tree().canonicalForm()));

		assertEquals(120L, firstResult.distinctCandidateCount(),
				"Four labelled factors have 4! * Catalan(3) oriented binary trees");
		assertEquals(120L,
				attempt(firstResult, ExhaustiveLegalJoinSearchContributor.ID).offeredCandidateCount(),
				"The exhaustive contributor must not make the service deduplicate repeated trees");
		assertEquals(first, second);
	}

	@Test
	void boundedEnumerationStopsAtCandidateBudgetAndReportsDeferredWork() throws ReflectiveOperationException {
		long candidateBudget = 7L;
		Method boundedEnumeration = JoinSearchRequest.class.getMethod("boundedEnumeration", JoinRegion.class,
				long.class, long.class, long.class);
		JoinSearchRequest request = (JoinSearchRequest) boundedEnumeration.invoke(null, region(5, List.of()), 0L, 0L,
				candidateBudget);
		AtomicInteger delivered = new AtomicInteger();

		JoinEnumerationResult result = new JoinSearchService(List.of(new ExhaustiveLegalJoinSearchContributor()))
				.enumerate(request, ignored -> delivered.incrementAndGet());
		JoinSearchResult.Attempt exhaustive = result.attempts()
				.stream()
				.filter(attempt -> attempt.descriptor().id().equals(ExhaustiveLegalJoinSearchContributor.ID))
				.findFirst()
				.orElseThrow();

		assertEquals(candidateBudget, delivered.get(), "bounded mode must stop at an exact deterministic boundary");
		assertEquals(candidateBudget, result.candidates().size());
		assertEquals(candidateBudget, exhaustive.offeredCandidateCount());
		assertEquals(JoinSearchContributor.Status.BUDGET_EXHAUSTED, exhaustive.outcome().status());
		assertEquals(JoinSearchCompleteness.BUDGET_EXHAUSTED, result.completeness());
		assertTrue(result.pendingReasons().stream().anyMatch(reason -> reason.contains("candidate budget")));
	}

